import { LayoutDashboard, GraduationCap, Microscope, Calculator, BookOpen, Atom } from "lucide-react";
import { getTranslations } from "next-intl/server";

export default async function Home({ params }: { params: Promise<{ locale: string }> }) {
    const { locale } = await params;
    const t = await getTranslations("Landing");

    const subjects = [
        {
            id: "math",
            name: t("subjects.math"),
            icon: <Calculator className="w-6 h-6 text-blue-600" />,
            color: "bg-blue-50"
        },
        {
            id: "physics",
            name: t("subjects.physics"),
            icon: <Atom className="w-6 h-6 text-indigo-600" />,
            color: "bg-indigo-50"
        },
        {
            id: "biology",
            name: t("subjects.biology"),
            icon: <Microscope className="w-6 h-6 text-emerald-600" />,
            color: "bg-emerald-50"
        },
        {
            id: "chemistry",
            name: t("subjects.chemistry"),
            icon: <Atom className="w-6 h-6 text-amber-600" />,
            color: "bg-amber-50"
        },
        {
            id: "english",
            name: t("subjects.english"),
            icon: <BookOpen className="w-6 h-6 text-rose-600" />,
            color: "bg-rose-50"
        },
    ];

    return (
        <main className="min-h-screen p-8 md:p-24 flex flex-col items-center">
            <div className="max-w-5xl w-full flex flex-col gap-12">
                {/* Header Section */}
                <section className="text-center space-y-6">
                    <h1 className="text-5xl md:text-7xl font-bold tracking-tight text-gradient">
                        {t("title")}
                    </h1>
                    <p className="text-xl text-slate-600 max-w-2xl mx-auto leading-relaxed">
                        {t("description")}
                    </p>
                </section>

                {/* Dashboard Preview / Subjects */}
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {subjects.map((subject) => (
                        <div
                            key={subject.id}
                            className="glass-card p-6 flex items-center gap-4 group cursor-pointer border-slate-200/50"
                        >
                            <div className={`p-4 rounded-2xl ${subject.color} group-hover:scale-105 transition-transform duration-300 shadow-sm`}>
                                {subject.icon}
                            </div>
                            <div>
                                <h3 className="text-xl font-semibold text-slate-800">{subject.name}</h3>
                                <p className="text-sm text-slate-500 font-medium">{t("subjects.specialization")}</p>
                            </div>
                        </div>
                    ))}

                    <div className="glass-panel p-6 flex flex-col justify-center items-center gap-2 border-dashed border-slate-300 hover:border-blue-400 bg-slate-50/50 transition-all cursor-not-allowed lg:col-span-1">
                        <LayoutDashboard className="w-8 h-8 text-slate-300" />
                        <span className="text-slate-400 font-semibold">{t("coming_soon")}</span>
                    </div>
                </div>

                {/* Call to Action */}
                <div className="glass-panel p-12 text-center space-y-8 bg-blue-50/30 border-blue-100/50 relative overflow-hidden">
                    <div className="absolute top-0 right-0 -mr-16 -mt-16 w-64 h-64 bg-blue-500/5 rounded-full blur-3xl" />
                    <div className="absolute bottom-0 left-0 -ml-16 -mb-16 w-64 h-64 bg-indigo-500/5 rounded-full blur-3xl" />

                    <GraduationCap className="w-20 h-20 mx-auto text-blue-600 mb-2 relative z-10" />
                    <div className="relative z-10 space-y-4">
                        <h2 className="text-4xl font-extrabold text-slate-800 tracking-tight">{t("cta")}</h2>
                        <p className="text-slate-600 text-lg max-w-xl mx-auto leading-relaxed font-medium">
                            {t("cta_desc")}
                        </p>
                        <button className="mt-4 px-10 py-4 bg-blue-600 hover:bg-blue-700 text-white text-lg font-bold rounded-2xl shadow-xl shadow-blue-500/20 hover:shadow-2xl transition-all duration-300 active:scale-95">
                            {t("begin")}
                        </button>
                    </div>
                </div>
            </div>
        </main>
    );
}
